  addr = strtonum("0x" $1)
  name = ""
  for (i=3; i<=NF; i++) name = name (i>3?" ":"") $i
  syms[n] = name; addrs[n] = addr; n++
}
END {
  targets[0] = 0x2f4b20; targets[1] = 0x2f4c84
