# The .text segment ends at 0x2ef810 (R+E). These addresses are in .data.rel.ro (RW).
# They may be erratum thunks or unwinder artifacts. Let's check if there's an
# __CortexA53843419 section or if these are indeed in executable memory.

# Check if there's a separate section for erratum thunks
aarch64-linux-gnu-readelf -W -S libmonosgen-2.0.so | grep -i -E 'cortex|errat|thunk'

echo "==="
# Look for all symbols in the range 0x2f4000-0x2f5000 in the debug file
aarch64-linux-gnu-objdump -t libmonosgen-2.0.so.dbg 2>/dev/null | awk '
{
  addr = strtonum("0x" $1)
  if (addr >= 0x2f4000 && addr <= 0x2f5000) print
}' | head -20

