aarch64-linux-gnu-readelf --unwind libmonosgen-2.0.so 2>/dev/null | awk '
/^0x/ {
  addr = strtonum($1)
  if (addr <= 0x2f4b20) { pa1 = addr; pn1 = $0 }
  if (addr <= 0x2f4c84) { pa2 = addr; pn2 = $0 }
}
END {
